57	  type two_process_r is record
58	    -- Registers always present
59	    Vld    : std_logic_vector(0 to 5);
60	    MultIQ : std_logic_vector(psi_fix_size(internal_fmt_g) - 1 downto 0);
61	    MultQI : std_logic_vector(psi_fix_size(internal_fmt_g) - 1 downto 0);
62	    MultII : std_logic_vector(psi_fix_size(internal_fmt_g) - 1 downto 0);
63	    MultQQ : std_logic_vector(psi_fix_size(internal_fmt_g) - 1 downto 0);
64	    SumI   : std_logic_vector(psi_fix_size(SumFmt_c) - 1 downto 0);
