69	    AiIn   : std_logic_vector(psi_fix_size(in_a_fmt_g) - 1 downto 0);
70	    AqIn   : std_logic_vector(psi_fix_size(in_a_fmt_g) - 1 downto 0);
71	    BiIn   : std_logic_vector(psi_fix_size(in_b_fmt_g) - 1 downto 0);
72	    BqIn   : std_logic_vector(psi_fix_size(in_b_fmt_g) - 1 downto 0);
73	    MrIQ   : std_logic_vector(psi_fix_size(internal_fmt_g) - 1 downto 0);
74	    MrQI   : std_logic_vector(psi_fix_size(internal_fmt_g) - 1 downto 0);
75	    MrII   : std_logic_vector(psi_fix_size(internal_fmt_g) - 1 downto 0);
76	    MrQQ   : std_logic_vector(psi_fix_size(internal_fmt_g) - 1 downto 0);
77	    RndI   : std_logic_vector(psi_fix_size(RndFmt_c) - 1 downto 0);
78	    RndQ   : std_logic_vector(psi_fix_size(RndFmt_c) - 1 downto 0);
79	  end record;
80	  signal r, r_next : two_process_r;
81	
82	begin
83	  --------------------------------------------
84	  -- Combinatorial Process
85	  --------------------------------------------
86	  p_comb : process(r, dat_inA_inp_i, dat_inA_qua_i, dat_inB_inp_i, dat_inB_qua_i, vld_i)
87	    variable v : two_process_r;
88	  begin
89	    -- *** Hold variables stable ***
90	    v := r;
91	
92	    -- *** Vld Handling ***
93	    v.Vld(0)      := vld_i;
94	    v.Vld(1 to 5) := r.Vld(0 to 4);
95	
96	    -- *** Multiplications ***
97	    if pipeline_g then
98	      v.AiIn := dat_inA_inp_i;
99	      v.AqIn := dat_inA_qua_i;
100	      v.BiIn := dat_inB_inp_i;
101	      v.BqIn := dat_inB_qua_i;
102	      v.MrIQ := r.MultIQ;
103	      v.MrQI := r.MultQI;
104	      v.MrII := r.MultII;
105	      v.MrQQ := r.MultQQ;
106	    end if;
107	    v.MultII := psi_fix_mult(choose(pipeline_g, r.AiIn, dat_inA_inp_i), in_a_fmt_g,
108	                           choose(pipeline_g, r.BiIn, dat_inB_inp_i), in_b_fmt_g, internal_fmt_g, psi_fix_trunc, psi_fix_wrap);
109	    if in_b_is_cplx_g then
110	      v.MultIQ := psi_fix_mult(choose(pipeline_g, r.AiIn, dat_inA_inp_i), in_a_fmt_g,
111	                             choose(pipeline_g, r.BqIn, dat_inB_qua_i), in_b_fmt_g, internal_fmt_g, psi_fix_trunc, psi_fix_wrap);
112	    else
113	      v.MultIQ := (others => '0');
114	    end if;
115	    if in_a_is_cplx_g then
116	      v.MultQI := psi_fix_mult(choose(pipeline_g, r.AqIn, dat_inA_qua_i), in_a_fmt_g,
117	                             choose(pipeline_g, r.BiIn, dat_inB_inp_i), in_b_fmt_g, internal_fmt_g, psi_fix_trunc, psi_fix_wrap);
118	    else
119	      v.MultQI := (others => '0');
120	    end if;
121	    if in_a_is_cplx_g and in_b_is_cplx_g then
122	      v.MultQQ := psi_fix_mult(choose(pipeline_g, r.AqIn, dat_inA_qua_i), in_a_fmt_g,
123	                             choose(pipeline_g, r.BqIn, dat_inB_qua_i), in_b_fmt_g, internal_fmt_g, psi_fix_trunc, psi_fix_wrap);
124	    else
125	      v.MultQQ := (others => '0');
126	    end if;
127	
128	    -- *** Additions ***
129	    v.SumI := psi_fix_sub(choose(pipeline_g, r.MrII, r.MultII), internal_fmt_g,
130	                        choose(pipeline_g, r.MrQQ, r.MultQQ), internal_fmt_g, SumFmt_c, psi_fix_trunc, psi_fix_wrap); -- no saturation/truncation occurs, format sufficient
131	    v.SumQ := psi_fix_add(choose(pipeline_g, r.MrIQ, r.MultIQ), internal_fmt_g,
132	                        choose(pipeline_g, r.MrQI, r.MultQI), internal_fmt_g, SumFmt_c, psi_fix_trunc, psi_fix_wrap); -- no saturation/truncation occurs, format sufficient
133	
134	    -- *** Resize ***
135	    if pipeline_g then
136	      v.RndI := psi_fix_resize(r.SumI, SumFmt_c, RndFmt_c, round_g, psi_fix_wrap); -- Never wrapps
137	      v.RndQ := psi_fix_resize(r.SumQ, SumFmt_c, RndFmt_c, round_g, psi_fix_wrap); -- Never wrapps
138	      v.OutI := psi_fix_resize(r.RndI, RndFmt_c, out_fmt_g, psi_fix_trunc, sat_g);
139	      v.OutQ := psi_fix_resize(r.RndQ, RndFmt_c, out_fmt_g, psi_fix_trunc, sat_g);
140	    else
141	      v.OutI := psi_fix_resize(r.SumI, SumFmt_c, out_fmt_g, round_g, sat_g);
142	      v.OutQ := psi_fix_resize(r.SumQ, SumFmt_c, out_fmt_g, round_g, sat_g);
143	    end if;
144	
145	    -- *** Assign to signal ***
146	    r_next <= v;
147	
148	  end process;
149	
150	  -- *** Outputs ***
151	  g_pl : if pipeline_g generate
152	    vld_o <= r.Vld(5);
153	  end generate;
154	  g_npl : if not pipeline_g generate
155	    vld_o <= r.Vld(2);
156	  end generate;
157	  dat_inp_o <= r.OutI;
158	  dat_qua_o <= r.OutQ;
159	
160	  --------------------------------------------
161	  -- Sequential Process
162	  --------------------------------------------
163	  p_seq : process(clk_i)
164	  begin
165	    if rising_edge(clk_i) then
166	      r <= r_next;
167	      if rst_i = rst_pol_g then
168	        r.Vld <= (others => '0');
169	      end if;
170	    end if;
171	  end process;
172	
173	end architecture;
