6	
7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	-- Add or Sub of two complex numbers
11	
12	------------------------------------------------------------------------------
13	-- Libraries
14	------------------------------------------------------------------------------
15	library ieee;
16	use ieee.std_logic_1164.all;
17	use ieee.numeric_std.all;
18	
19	use work.psi_fix_pkg.all;
20	use work.psi_common_math_pkg.all;
21	-- @formatter:off
22	------------------------------------------------------------------------------
23	-- Entity Declaration
24	------------------------------------------------------------------------------
25	-- $$ processes=stim, resp $$
26	entity psi_fix_complex_addsub is
27	  generic(rst_pol_g   : std_logic   := '1';                                         -- set reset polarity                $$ constant='1' $$
28	          pipeline_g  : boolean     := false;                                       -- when false 3 pipes stages, when false 6 pipes (increase Fmax)      $$ export=true $$
29	          in_a_fmt_g  : psi_fix_fmt_t := (1, 0, 15);                                -- Input A Fixed Point format   $$ constant=(1,0,15) $$
30	          in_b_fmt_g  : psi_fix_fmt_t := (1, 0, 24);                                -- Input B Fixed Point format   $$ constant=(1,0,24) $$
31	          out_fmt_g   : psi_fix_fmt_t := (1, 0, 20);                                -- Output Fixed Point format    $$ constant=(1,0,20) $$
32	          round_g     : psi_fix_rnd_t := psi_fix_round;                             -- Round or trunc  $$ constant=psi_fix_round $$
33	          sat_g       : psi_fix_sat_t := psi_fix_sat;                               -- Adder or Subtracter  $$ constant=psi_fix_sat $$
34	          add_sub_g   : string      := "ADD");
35	  port(clk_i         : in  std_logic;                                               -- clk    $$ type=clk; freq=100e6 $$
36	       rst_i         : in  std_logic;                                               -- sync. rst    $$ type=rst; clk=clk_i $$
37	       dat_inA_inp_i : in  std_logic_vector(psi_fix_size(in_a_fmt_g) - 1 downto 0); -- Inphase input of signal A
38	       dat_inA_qua_i : in  std_logic_vector(psi_fix_size(in_a_fmt_g) - 1 downto 0); -- Quadrature input of signal A
39	       dat_inB_inp_i : in  std_logic_vector(psi_fix_size(in_b_fmt_g) - 1 downto 0); -- Inphase input of signal B
40	       dat_inB_qua_i : in  std_logic_vector(psi_fix_size(in_b_fmt_g) - 1 downto 0); -- Quadrature input of signal B
41	       vld_i         : in  std_logic;                                               -- strobe input
42	       dat_out_inp_o : out std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);  -- data output I
43	       dat_out_qua_o : out std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);  -- data output Q
44	       vld_o         : out std_logic                                                -- strobe output
45	      );
46	begin
47	  assert add_sub_g = "ADD" or add_sub_g = "SUB"
48	  report "AddSub generic value is wrong! must be ADD or SUB" severity error;
49	end entity;
50	-- @formatter:on
51	------------------------------------------------------------------------------
52	-- Architecture Declaration
53	------------------------------------------------------------------------------
54	architecture rtl of psi_fix_complex_addsub is
55	
56	  constant SumFmt_c : psi_fix_fmt_t := (max(in_a_fmt_g.S, in_b_fmt_g.S), max(in_a_fmt_g.I, in_b_fmt_g.I) + 1, max(in_a_fmt_g.F, in_b_fmt_g.F));
57	  constant RndFmt_c : psi_fix_fmt_t := (SumFmt_c.S, SumFmt_c.I + 1, out_fmt_g.F);
58	
59	  -- Two process method
60	  type two_process_r is record
61	    -- Registers always present
62	    Vld   : std_logic_vector(0 to 3);
63	
64	    AddII : std_logic_vector(psi_fix_size(SumFmt_c) - 1 downto 0);
65	    AddQQ : std_logic_vector(psi_fix_size(SumFmt_c) - 1 downto 0);
66	
67	    OutI  : std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);
68	    OutQ  : std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);
69	    -- Additional registers for pipelined version
70	    AiIn  : std_logic_vector(psi_fix_size(in_a_fmt_g) - 1 downto 0);
71	    AqIn  : std_logic_vector(psi_fix_size(in_a_fmt_g) - 1 downto 0);
72	    BiIn  : std_logic_vector(psi_fix_size(in_b_fmt_g) - 1 downto 0);
73	    BqIn  : std_logic_vector(psi_fix_size(in_b_fmt_g) - 1 downto 0);
74	    --
75	    RndI  : std_logic_vector(psi_fix_size(RndFmt_c) - 1 downto 0);
76	    RndQ  : std_logic_vector(psi_fix_size(RndFmt_c) - 1 downto 0);
77	  end record;
78	  signal r, r_next : two_process_r;
79	
80	begin
81	  --------------------------------------------
82	  -- Combinatorial Process
83	  --------------------------------------------
84	  p_comb : process(r, dat_inA_inp_i, dat_inA_qua_i, dat_inB_inp_i, dat_inB_qua_i, vld_i)
85	    variable v : two_process_r;
86	  begin
87	    -- *** Hold variables stable ***
88	    v := r;
89	
90	    -- *** Vld Handling ***
91	    v.Vld(0)      := vld_i;
92	    v.Vld(1 to 3) := r.Vld(0 to 2);
93	
94	    -- *** pipeline ***
95	    if pipeline_g then
96	      v.AiIn := dat_inA_inp_i;
97	      v.AqIn := dat_inA_qua_i;
98	      v.BiIn := dat_inB_inp_i;
99	      v.BqIn := dat_inB_qua_i;
100	    end if;
101	    --*** Add or Sub ***
102	    if add_sub_g = "ADD" then
103	      v.AddII := psi_fix_add(choose(pipeline_g, r.AiIn, dat_inA_inp_i), in_a_fmt_g,
104	                           choose(pipeline_g, r.BiIn, dat_inB_inp_i), in_b_fmt_g, SumFmt_c, psi_fix_trunc, psi_fix_wrap);
105	      v.AddQQ := psi_fix_add(choose(pipeline_g, r.AqIn, dat_inA_qua_i), in_a_fmt_g,
106	                           choose(pipeline_g, r.BqIn, dat_inB_qua_i), in_b_fmt_g, SumFmt_c, psi_fix_trunc, psi_fix_wrap);
107	    elsif add_sub_g = "SUB" then
108	      v.AddII := psi_fix_sub(choose(pipeline_g, r.AiIn, dat_inA_inp_i), in_a_fmt_g,
109	                           choose(pipeline_g, r.BiIn, dat_inB_inp_i), in_b_fmt_g, SumFmt_c, psi_fix_trunc, psi_fix_wrap);
110	      v.AddQQ := psi_fix_sub(choose(pipeline_g, r.AqIn, dat_inA_qua_i), in_a_fmt_g,
111	                           choose(pipeline_g, r.BqIn, dat_inB_qua_i), in_b_fmt_g, SumFmt_c, psi_fix_trunc, psi_fix_wrap);
112	    end if;
113	    -- *** Resize ***
114	    if pipeline_g then
115	      v.RndI := psi_fix_resize(r.AddII, SumFmt_c, RndFmt_c, round_g, psi_fix_wrap); -- Never wrapps
116	      v.RndQ := psi_fix_resize(r.AddQQ, SumFmt_c, RndFmt_c, round_g, psi_fix_wrap); -- Never wrapps
117	      v.OutI := psi_fix_resize(r.RndI, RndFmt_c, out_fmt_g, psi_fix_trunc, sat_g);
118	      v.OutQ := psi_fix_resize(r.RndQ, RndFmt_c, out_fmt_g, psi_fix_trunc, sat_g);
119	    else
120	      v.OutI := psi_fix_resize(r.AddII, SumFmt_c, out_fmt_g, round_g, sat_g);
121	      v.OutQ := psi_fix_resize(r.AddQQ, SumFmt_c, out_fmt_g, round_g, sat_g);
122	    end if;
123	
124	    -- *** Assign to signal ***
125	    r_next <= v;
126	
127	  end process;
128	
