1	------------------------------------------------------------------------------
2	--  Copyright (c) 2018 by Paul Scherrer Institute, Switzerland
3	--  All rights reserved.
4	--  Authors: Oliver Bruendler
5	------------------------------------------------------------------------------
6	
7	------------------------------------------------------------------------------
8	-- Libraries
9	------------------------------------------------------------------------------
10	library ieee;
11	use ieee.std_logic_1164.all;
12	use ieee.numeric_std.all;
13	use ieee.math_real.all;
14	
15	use work.psi_common_array_pkg.all;
16	use work.psi_common_math_pkg.all;
17	use work.psi_fix_pkg.all;
18	use work.psi_common_logic_pkg.all;
19	-- @formatter:off
20	-- $$ tbpkg=psi_lib.psi_tb_textfile_pkg,psi_lib.psi_tb_txt_util $$
21	-- $$ processes=stimuli,response $$
22	entity psi_fix_complex_abs is
23	  generic(
24	    in_fmt_g       : psi_fix_fmt_t := (1, 0, 15);                            -- FP format in
25	    out_fmt_g      : psi_fix_fmt_t := (0, 1, 15);                            -- FP format out
26	    round_g        : psi_fix_rnd_t := psi_fix_trunc;                         -- trunc or round
27	    sat_g          : psi_fix_sat_t := psi_fix_wrap;                          -- Wrap or sat
28	    rst_pol_g      : std_logic   := '1';                                     -- reset polarity active high
29	    ram_behavior_g : string      := "RBW"                                    -- RBW = Read before write, WBR = write before read
30	  );
31	  port(
32	    clk_i     : in  std_logic;                                              -- $$ type=Clk; freq=127e6 $$
33	    rst_i     : in  std_logic;                                              -- $$ type=Rst; Clk=clk_i $$
34	    dat_inp_i : in  std_logic_vector(psi_fix_size(in_fmt_g) - 1 downto 0);  -- data inphase I
35	    dat_qua_i : in  std_logic_vector(psi_fix_size(in_fmt_g) - 1 downto 0);  -- data quadrature Q
36	    vld_i     : in  std_logic;                                              -- valid signal in
37	    dat_o     : out std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0); -- results output DQRT(I^2+Q^2)
38	    vld_o     : out std_logic                                               -- valid signal out
39	  );
40	end entity;
41	-- @formatter:on
42	------------------------------------------------------------------------------
43	-- Architecture section
44	------------------------------------------------------------------------------
45	
46	architecture rtl of psi_fix_complex_abs is
47	
48	  -- Constants
49	  constant InFmtNorm_c          : psi_fix_fmt_t := (in_fmt_g.S, 0, in_fmt_g.I + in_fmt_g.F);
50	  constant OutFmtNorm_c         : psi_fix_fmt_t := (out_fmt_g.S, 0, out_fmt_g.I + out_fmt_g.F + 1); -- rounding bit is kept
51	  constant SqrFmt_c             : psi_fix_fmt_t := (0, InFmtNorm_c.I + 1, InFmtNorm_c.F * 2);
52	  constant AddFmt_c             : psi_fix_fmt_t := (0, SqrFmt_c.I + 1, SqrFmt_c.F);
53	  constant LimFmt_c             : psi_fix_fmt_t := (0, 0, AddFmt_c.F); -- 2*15=30 fractional bits
54	  constant SqrtInFmt_c          : psi_fix_fmt_t := (0, 0, 20);
55	  constant SqrtOutFmt_c         : psi_fix_fmt_t := (0, 0, 17);
56	  constant MaxSft_c             : natural     := (InFmtNorm_c.F / 2 * 2);
57	  constant SftStgBeforeApprox_c : natural     := log2ceil(MaxSft_c);
58	  constant SftStgAfterApprox_c  : natural     := SftStgBeforeApprox_c / 2;
59	  constant OutSftFmt_c          : psi_fix_fmt_t := (0, 0, OutFmtNorm_c.F);
60	
61	  -- types
62	  type LimArray_t is array (natural range <>) of std_logic_vector(psi_fix_size(LimFmt_c) - 1 downto 0);
63	  type CntArray_t is array (natural range <>) of unsigned(SftStgBeforeApprox_c - 1 downto 0);
64	  type OutSftArray_t is array (natural range <>) of std_logic_vector(psi_fix_size(OutSftFmt_c) - 1 downto 0);
65	
66	  -- Two Process Method
67	  type two_process_r is record
68	    InVld  : std_logic_vector(0 to 4 + SftStgBeforeApprox_c - 1);
69	    I_0    : std_logic_vector(psi_fix_size(InFmtNorm_c) - 1 downto 0);
70	    Q_0    : std_logic_vector(psi_fix_size(InFmtNorm_c) - 1 downto 0);
71	    ISqr_1 : std_logic_vector(psi_fix_size(SqrFmt_c) - 1 downto 0);
72	    QSqr_1 : std_logic_vector(psi_fix_size(SqrFmt_c) - 1 downto 0);
73	    Sum_2  : std_logic_vector(psi_fix_size(AddFmt_c) - 1 downto 0);
74	    Lim_3  : std_logic_vector(psi_fix_size(LimFmt_c) - 1 downto 0);
75	    InSft  : LimArray_t(0 to SftStgBeforeApprox_c - 1);
76	    SftCnt : CntArray_t(0 to SftStgBeforeApprox_c - 1);
77	    OutVld : std_logic_vector(0 to SftStgAfterApprox_c + 1);
78	    OutSft : OutSftArray_t(0 to SftStgAfterApprox_c);
79	    OutCnt : CntArray_t(0 to SftStgAfterApprox_c);
80	    OutRes : std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);
81	  end record;
82	  signal r, r_next : two_process_r;
83	
84	  -- Component Instantiation
85	  signal SqrtIn_s    : std_logic_vector(psi_fix_size(SqrtInFmt_c) - 1 downto 0);
86	  signal SftCntOut_s : std_logic_vector(SftStgBeforeApprox_c - 1 downto 0);
87	  signal IsZeroIn_s  : std_logic;
88	  signal IsZeroOut_s : std_logic;
89	  signal SqrtVld_s   : std_logic;
90	  signal SqrtData_s  : std_logic_vector(psi_fix_size(SqrtOutFmt_c) - 1 downto 0);
91	
92	begin
93	  --------------------------------------------------------------------------
94	  -- Combinatorial Process
95	  --------------------------------------------------------------------------
96	  proc_comb : process(r, vld_i, dat_inp_i, dat_qua_i, SftCntOut_s, SqrtVld_s, SqrtData_s, IsZeroOut_s)
97	    variable v              : two_process_r;
98	    variable SftBeforeIn_v  : std_logic_vector(psi_fix_size(LimFmt_c) - 1 downto 0);
99	    variable SftBefore_v    : integer;
100	    variable SftAfter_v     : unsigned(SftStgBeforeApprox_c downto 0);
101	    variable SftStepAfter_v : integer;
102	    variable StgIdx_v       : integer;
103	  begin
104	    -- hold variables stable
105	    v := r;
106	
107	    -- *** Pipe Handling ***
108	    v.InVld(v.InVld'low + 1 to v.InVld'high)    := r.InVld(r.InVld'low to r.InVld'high - 1);
109	    v.OutVld(v.OutVld'low + 1 to v.OutVld'high) := r.OutVld(r.OutVld'low to r.OutVld'high - 1);
110	
111	    -- *** Stage 0 ***
112	    -- Input Registers
113	    v.InVld(0) := vld_i;
114	    v.I_0      := dat_inp_i;
115	    v.Q_0      := dat_qua_i;
116	
117	    -- *** Stage 1 ***
118	    -- Normalization is implicit by reinterpreting the number format (number of bits is not changed)
119	
120	    -- Squaring
121	    v.ISqr_1 := psi_fix_mult(r.I_0, InFmtNorm_c, r.I_0, InFmtNorm_c, SqrFmt_c);
122	    v.QSqr_1 := psi_fix_mult(r.Q_0, InFmtNorm_c, r.Q_0, InFmtNorm_c, SqrFmt_c);
123	
124	    -- *** Stage 2 ***
125	    -- Sum
126	    v.Sum_2 := psi_fix_add(r.ISqr_1, SqrFmt_c, r.QSqr_1, SqrFmt_c, AddFmt_c);
127	
128	    -- *** Stage 3 ***
129	    -- Limit to 1
130	    v.Lim_3 := psi_fix_resize(r.Sum_2, AddFmt_c, LimFmt_c, psi_fix_trunc, psi_fix_sat);
131	
132	    -- *** Shift stages (0 ... x) ***
133	    for stg in 0 to SftStgBeforeApprox_c - 1 loop
134	      -- Select input
135	      if stg = 0 then
136	        SftBeforeIn_v := r.Lim_3;
137	        v.SftCnt(stg) := (others => '0');
138	      else
139	        SftBeforeIn_v := r.InSft(stg - 1);
140	        v.SftCnt(stg) := r.SftCnt(stg - 1);
141	      end if;
142	
143	      -- Do Shift
144	      SftBefore_v := 2**(SftStgBeforeApprox_c - stg);
145	      if unsigned(SftBeforeIn_v(SftBeforeIn_v'left downto SftBeforeIn_v'left - SftBefore_v + 1)) = 0 then
146	        v.InSft(stg)                                  := SftBeforeIn_v(SftBeforeIn_v'left - SftBefore_v downto 0) & zeros_vector(SftBefore_v);
147	        v.SftCnt(stg)(SftStgBeforeApprox_c - stg - 1) := '1';
148	      else
149	        v.InSft(stg)                                  := SftBeforeIn_v;
150	        v.SftCnt(stg)(SftStgBeforeApprox_c - stg - 1) := '0';
151	      end if;
152	    end loop;
153	
154	    -- *** Out Stage 0 ***
155	    v.OutVld(0) := SqrtVld_s;
156	    if IsZeroOut_s = '1' then
157	      v.OutSft(0) := (others => '0');
158	    else
159	      v.OutSft(0) := psi_fix_resize(SqrtData_s, SqrtOutFmt_c, OutSftFmt_c);
160	    end if;
161	    v.OutCnt(0) := unsigned(SftCntOut_s);
162	
163	    -- *** Out Shift Stages ***
164	    for stg in 0 to SftStgAfterApprox_c - 1 loop
165	      -- Zero extend shift
166	      SftAfter_v := resize(r.OutCnt(stg), SftAfter_v'length);
167	
168	      -- Shift
169	      v.OutCnt(stg + 1) := r.OutCnt(stg);
170	      StgIdx_v          := SftStgAfterApprox_c - 1 - stg;
171	      SftStepAfter_v    := 2**(2 * (StgIdx_v));
172	      v.OutSft(stg + 1) := psi_fix_shift_right(r.OutSft(stg), OutFmtNorm_c, to_integer(r.OutCnt(stg)(2 * StgIdx_v + 1 downto 2 * StgIdx_v)) * SftStepAfter_v, 3 * SftStepAfter_v, OutFmtNorm_c, psi_fix_trunc, psi_fix_wrap, true);
173	    end loop;
174	
175	    -- *** Output resize ***
176	    v.OutRes := psi_fix_shift_left(r.OutSft(r.OutSft'high), OutFmtNorm_c, in_fmt_g.I, in_fmt_g.I, out_fmt_g, round_g, sat_g);
177	
178	    -- Apply to record
